class Solution {
public:
    bool canConvertString(string s, string t, int k) {
        int m = s.length();
        int n = t.length();

        // Check if s and t have the same length
        if (m != n) return false;

        // Check if k is greater than the number of characters in s
        if (k > m) return false;

        // Create a map to store the frequency of each character in s
        unordered_map<char, int> freqMap;

        // Iterate through s and update the frequency of each character in freqMap
        for (char c : s) {
            freqMap[c]++;
        }

        // Iterate through t and check if all characters in t can be formed using the characters in freqMap
        for (char c : t) {
            if (freqMap[c] == 0) return false;
            freqMap[c]--;
        }

        // Return true if k is less than or equal to the number of characters in s, and all characters in t can be formed using the characters in freqMap
        return k <= m && t.length() <= m && freqMap.size() <= m;
    }
};
